(function(){const e=document.getElementById("theme-toggle");if(!e)return;function t(e){return e==="dark"?"Switch to light theme":"Switch to dark theme"}e.setAttribute("aria-label",t(document.documentElement.getAttribute("data-theme"))),e.addEventListener("click",function(){const s=document.documentElement,n=s.getAttribute("data-theme")==="dark"?"light":"dark";s.setAttribute("data-theme",n),localStorage.setItem("theme",n),e.setAttribute("aria-label",t(n))})})()